      {
        "tool": "read_file",
        "args": {
          "path": ".agent/rules/DATAPACK_RULES.md"
        }
      }
    ]
  }
}

{
  "title": "Validate Environment & Version",
  "thought": "Following Step 2 of the workflow: Validate the Minecraft version and Pack Format using the authoritative tool.",
  "decision": {
    "type": "execute_action",
    "tool": "run_command",
    "args": {
      "command": "python .agent/tools/version/validate_version.py"
    }
  }
}

{
  "title": "Tool Discovery",
  "thought": "I will list the `.agent/tools` directory to discover available capabilities as per Step 3 of the Project Scan workflow.",
  "decision": {
    "type": "execute_action",
    "tool": "list_directory",
    "args": {
      "path": ".agent/tools",
      "max_depth": 2
    }
  }
}

{
  "title": "Scan Project Structure - Step 1 & 2",
  "thought": "Reading pack.mcmeta and listing the data directory to identify namespaces and verify version compatibility.",
  "decision": {
    "type": "execute_actions",
    "actions": [
      {
        "tool": "read_file",
        "args": {
          "path": "pack.mcmeta"
        }
      },
      {
        "tool": "list_directory",
        "args": {
          "path": "data",
          "max_depth": 1
        }
      }
    ]
  }
}

